@app.route('/api/users/&lt;int:user_id&gt;/preferences', methods=['PUT'])
def update_preferences(user_id):
    db = get_db()
    user = db.get_user_by_id(user_id)

    if not user:
        return jsonify({'error': 'User not found'}), 404

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    valid_sensitivities = ['low', 'medium', 'high']
    for field in [
        'language_sensitivity',
        'sexual_content_sensitivity',
        'violence_sensitivity',
    ]:
        if field in data and data[field] not in valid_sensitivities:
            return jsonify({
                'error': f'Invalid {field}. Must be one of: {", ".join(valid_sensitivities)}',
            }), 400

    success = db.update_user_preferences(user_id, data)
    if not success:
        return jsonify({'error': 'Failed to update preferences'}), 500

    return jsonify({
        'message': 'Preferences updated successfully',
        'preferences': db.get_user_preferences(user_id),
    }), 200


